#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const { loadRecipeRelations } = require('../recipes/recipe-relations');

const GENERATED_NOTICE = [
	'<!--',
	'This file is auto-generated by scripts/functions/generate-function-docs.js.',
	'Do not edit manually.',
	'-->',
	'',
].join('\n');

function parseArgs() {
	const args = {};

	process.argv.slice(2).forEach((arg) => {
		const [rawKey, ...valueParts] = arg.replace(/^--/, '').split('=');
		const value = valueParts.join('=');
		args[rawKey] = value === '' ? true : value;
	});

	return args;
}

function readJson(filePath) {
	if (!fs.existsSync(filePath)) {
		throw new Error(`File not found: ${filePath}`);
	}

	return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function escapeMdxText(value) {
	if (typeof value !== 'string') {
		return '';
	}

	return value.replace(/[{}]/g, '\\$&');
}

function ensureDir(dirPath) {
	if (!fs.existsSync(dirPath)) {
		fs.mkdirSync(dirPath, { recursive: true });
	}
}

function listMarkdownFiles(dirPath) {
	if (!fs.existsSync(dirPath)) {
		return [];
	}

	return fs
		.readdirSync(dirPath)
		.filter((name) => name.endsWith('.md'))
		.map((name) => path.join(dirPath, name));
}

function normalizeRepoUrl(repoUrl) {
	if (!repoUrl || typeof repoUrl !== 'string') {
		return null;
	}

	const trimmed = repoUrl.trim();
	if (!trimmed) {
		return null;
	}

	if (trimmed.startsWith('git@github.com:')) {
		return trimmed
			.replace(/^git@github\.com:/, 'https://github.com/')
			.replace(/\.git$/, '');
	}

	if (trimmed.startsWith('https://github.com/')) {
		return trimmed.replace(/\.git$/, '');
	}

	return trimmed.replace(/\.git$/, '');
}

function resolveRepositoryUrl({ args, pluginConfig, repoRoot }) {
	const fromArgs = normalizeRepoUrl(args['repo-url']);
	if (fromArgs) {
		return fromArgs;
	}

	const fromConfig = normalizeRepoUrl(pluginConfig.repositoryUrl);
	if (fromConfig) {
		return fromConfig;
	}

	try {
		const remoteUrl = execSync('git remote get-url origin', {
			cwd: repoRoot,
			encoding: 'utf8',
			stdio: ['ignore', 'pipe', 'ignore'],
		}).trim();
		return normalizeRepoUrl(remoteUrl);
	} catch (_error) {
		return null;
	}
}

function resolveRepositoryRef({ args, pluginConfig, repoRoot }) {
	const fromArgs = typeof args['repo-ref'] === 'string' ? args['repo-ref'].trim() : '';
	if (fromArgs) {
		return fromArgs;
	}

	const fromConfig =
		typeof pluginConfig.repositoryRef === 'string' ? pluginConfig.repositoryRef.trim() : '';
	if (fromConfig) {
		return fromConfig;
	}

	try {
		const originHead = execSync('git symbolic-ref refs/remotes/origin/HEAD', {
			cwd: repoRoot,
			encoding: 'utf8',
			stdio: ['ignore', 'pipe', 'ignore'],
		}).trim();
		const branch = originHead.split('/').pop();
		return branch || 'main';
	} catch (_error) {
		return 'main';
	}
}

function buildRepositoryFileUrl({ repositoryUrl, repositoryRef, filePath, line }) {
	if (!repositoryUrl || !repositoryRef || !filePath) {
		return null;
	}

	const encodedSegments = filePath
		.split('/')
		.map((segment) => encodeURIComponent(segment))
		.join('/');
	const lineAnchor = line ? `#L${line}` : '';
	return `${repositoryUrl}/blob/${encodeURIComponent(repositoryRef)}/${encodedSegments}${lineAnchor}`;
}

function slugFromFunctionName(name) {
	return name.toLowerCase().replace(/[^a-z0-9_-]+/g, '-');
}

function getLineNumber(content, index) {
	return content.slice(0, index).split('\n').length;
}

function getNearestDocblock(content, index) {
	const prefix = content.slice(0, index);
	const docblockEnd = prefix.lastIndexOf('*/');
	if (docblockEnd === -1) {
		return null;
	}

	const docblockStart = prefix.lastIndexOf('/**', docblockEnd);
	if (docblockStart === -1) {
		return null;
	}

	const between = content.slice(docblockEnd + 2, index);
	const betweenWithoutComments = between
		.replace(/^\s*\/\/.*$/gm, '')
		.replace(/^\s*#.*$/gm, '')
		.trim();
	if (betweenWithoutComments !== '') {
		return null;
	}

	return content.slice(docblockStart, docblockEnd + 2);
}

function parseDocblock(rawDocblock) {
	if (!rawDocblock) {
		return {
			description: '',
			since: null,
			functionGroup: null,
			params: [],
			returnTag: null,
			throws: [],
		};
	}

	const lines = rawDocblock
		.replace(/^\/\*\*/, '')
		.replace(/\*\/$/, '')
		.split('\n')
		.map((line) => line.replace(/^\s*\*\s?/, '').trimEnd());

	const descriptionLines = [];
	const params = [];
	const throws = [];
	let since = null;
	let functionGroup = null;
	let returnTag = null;
	let currentTag = null;
	let inTags = false;

	lines.forEach((line) => {
		const trimmed = line.trim();
		if (!trimmed) {
			currentTag = null;
			return;
		}

		if (trimmed.startsWith('@')) {
			inTags = true;
		}

		if (!inTags) {
			descriptionLines.push(trimmed);
			return;
		}

		const paramMatch = trimmed.match(/^@param\s+(\S+)\s+(\$\S+)\s*(.*)$/);
		if (paramMatch) {
			params.push({
				type: paramMatch[1],
				name: paramMatch[2],
				description: paramMatch[3] || '',
			});
			currentTag = { type: 'param', index: params.length - 1 };
			return;
		}

		const returnMatch = trimmed.match(/^@return\s+(\S+)\s*(.*)$/);
		if (returnMatch) {
			returnTag = {
				type: returnMatch[1],
				description: returnMatch[2] || '',
			};
			currentTag = { type: 'return' };
			return;
		}

		const throwsMatch = trimmed.match(/^@throws\s+(\S+)\s*(.*)$/);
		if (throwsMatch) {
			throws.push({
				type: throwsMatch[1],
				description: throwsMatch[2] || '',
			});
			currentTag = { type: 'throws', index: throws.length - 1 };
			return;
		}

		const sinceMatch = trimmed.match(/^@since\s+(.+)$/);
		if (sinceMatch) {
			since = sinceMatch[1].trim();
			currentTag = null;
			return;
		}

		const functionGroupMatch = trimmed.match(/^@functionGroup\s+(.+)$/i);
		if (functionGroupMatch) {
			functionGroup = functionGroupMatch[1].trim();
			currentTag = null;
			return;
		}

		if (trimmed.startsWith('@')) {
			currentTag = null;
			return;
		}

		if (currentTag?.type === 'param') {
			params[currentTag.index].description = `${params[currentTag.index].description} ${trimmed}`.trim();
		} else if (currentTag?.type === 'return' && returnTag) {
			returnTag.description = `${returnTag.description} ${trimmed}`.trim();
		} else if (currentTag?.type === 'throws') {
			throws[currentTag.index].description = `${throws[currentTag.index].description} ${trimmed}`.trim();
		}
	});

	return {
		description: descriptionLines.join(' ').trim(),
		since,
		functionGroup,
		params,
		returnTag,
		throws,
	};
}

function splitTopLevelParams(paramsSource) {
	const params = [];
	let current = '';
	let depthParen = 0;
	let depthBracket = 0;
	let depthBrace = 0;
	let inString = null;
	let isEscaped = false;

	for (let i = 0; i < paramsSource.length; i++) {
		const char = paramsSource[i];

		if (inString) {
			current += char;
			if (!isEscaped && char === inString) {
				inString = null;
			}
			isEscaped = !isEscaped && char === '\\';
			continue;
		}

		if (char === '"' || char === '\'') {
			inString = char;
			isEscaped = false;
			current += char;
			continue;
		}

		if (char === '(') {
			depthParen++;
			current += char;
			continue;
		}
		if (char === ')') {
			depthParen--;
			current += char;
			continue;
		}
		if (char === '[') {
			depthBracket++;
			current += char;
			continue;
		}
		if (char === ']') {
			depthBracket--;
			current += char;
			continue;
		}
		if (char === '{') {
			depthBrace++;
			current += char;
			continue;
		}
		if (char === '}') {
			depthBrace--;
			current += char;
			continue;
		}

		if (char === ',' && depthParen === 0 && depthBracket === 0 && depthBrace === 0) {
			params.push(current.trim());
			current = '';
			continue;
		}

		current += char;
	}

	if (current.trim()) {
		params.push(current.trim());
	}

	return params.filter(Boolean);
}

function normalizeSignature(declaration) {
	const compact = declaration.replace(/\s+/g, ' ').trim();
	return compact.replace(/^function\s+/, '');
}

function extractFunctionsFromContent(content, sourcePath) {
	const functions = [];
	const functionRegex = /(^|\n)\s*function\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(/g;

	let match = functionRegex.exec(content);
	while (match) {
		const functionName = match[2];
		const functionIndex = match.index + match[1].length + match[0].slice(match[1].length).indexOf('function');

		let i = functionIndex;
		while (i < content.length && content[i] !== '{') {
			i++;
		}

		if (i >= content.length) {
			match = functionRegex.exec(content);
			continue;
		}

		const declaration = content.slice(functionIndex, i).trim();
		const paramsSourceMatch = declaration.match(/\(([\s\S]*)\)/);
		const paramsSource = paramsSourceMatch ? paramsSourceMatch[1] : '';
		const signature = normalizeSignature(declaration);
		const parameterTokens = splitTopLevelParams(paramsSource);
		const parameterNames = parameterTokens
			.map((token) => {
				const nameMatch = token.match(/(\$[A-Za-z_][A-Za-z0-9_]*)/);
				return nameMatch ? nameMatch[1] : null;
			})
			.filter(Boolean);

		const returnTypeMatch = declaration.match(/\)\s*:\s*([^\s{]+)/);
		const returnType = returnTypeMatch ? returnTypeMatch[1] : null;
		const docblock = parseDocblock(getNearestDocblock(content, functionIndex));

		functions.push({
			name: functionName,
			signature,
			sourceSnippet: `${declaration} {`,
			parameterNames,
			returnType,
			file: sourcePath,
			line: getLineNumber(content, functionIndex),
			docblock,
		});

		match = functionRegex.exec(content);
	}

	return functions;
}

function analyzeLint(functions) {
	const warnings = [];

	functions.forEach((fn) => {
		const context = {
			function: fn.name,
			file: fn.file,
			line: fn.line,
		};

		if (!fn.docblock.description) {
			warnings.push({
				type: 'missing_function_description',
				message: 'Missing function description in nearest docblock',
				...context,
			});
		}

		if (!fn.docblock.since) {
			warnings.push({
				type: 'missing_function_since',
				message: 'Missing @since tag in nearest docblock',
				...context,
			});
		}

		if (fn.parameterNames.length > 0 && fn.docblock.params.length === 0) {
			warnings.push({
				type: 'missing_function_params',
				message: 'Function has parameters but docblock is missing @param entries',
				...context,
			});
		}

		if (
			fn.parameterNames.length > 0 &&
			fn.docblock.params.length > 0 &&
			fn.docblock.params.length < fn.parameterNames.length
		) {
			warnings.push({
				type: 'function_param_count_mismatch',
				message: `Function has ${fn.parameterNames.length} parameter(s) but only ${fn.docblock.params.length} @param tag(s)`,
				...context,
			});
		}

		const missingParamNames = fn.parameterNames.filter(
			(name) => !fn.docblock.params.some((param) => param.name === name)
		);
		if (missingParamNames.length > 0) {
			warnings.push({
				type: 'missing_function_param_doc',
				message: `Missing @param docs for: ${missingParamNames.join(', ')}`,
				...context,
			});
		}

		fn.docblock.params.forEach((param, index) => {
			if (!param.description) {
				warnings.push({
					type: 'missing_function_param_description',
					message: `@param entry ${index + 1} (${param.name}) is missing a description`,
					...context,
				});
			}
		});

		if (!fn.docblock.returnTag && fn.returnType !== 'void') {
			warnings.push({
				type: 'missing_function_return',
				message: 'Missing @return tag in nearest docblock',
				...context,
			});
		}
	});

	return {
		errors: [],
		warnings,
	};
}

function renderFunctionDoc(fn, repositoryUrl, repositoryRef) {
	const lines = [];
	const relatedRecipes = fn.relatedRecipes || [];
	const sourceUrl = buildRepositoryFileUrl({
		repositoryUrl,
		repositoryRef,
		filePath: fn.file,
		line: fn.line,
	});

	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push(`title: ${fn.name}`);
	lines.push('docType: function');
	lines.push('plugin: wp-graphql');
	lines.push('---');
	lines.push('');
	lines.push(`# ${fn.name}`);
	lines.push('');
	lines.push('```php');
	lines.push(`${fn.signature};`);
	lines.push('```');
	lines.push('');
	lines.push(escapeMdxText(fn.docblock.description || 'No description available.'));
	lines.push('');
	lines.push(`- **Since:** ${fn.docblock.since || 'Unknown'}`);
	lines.push(`- **Source File:** \`${fn.file}\``);
	lines.push('');

	if (fn.docblock.params.length > 0) {
		lines.push('## Parameters');
		lines.push('');
		fn.docblock.params.forEach((param) => {
			lines.push(
				`- \`${param.name}\` (\`${param.type}\`): ${escapeMdxText(param.description || 'No description.')}`
			);
		});
		lines.push('');
	}

	if (fn.docblock.returnTag) {
		lines.push('## Return');
		lines.push('');
		lines.push(
			`- \`${fn.docblock.returnTag.type}\`${fn.docblock.returnTag.description ? `: ${escapeMdxText(fn.docblock.returnTag.description)}` : ''}`
		);
		lines.push('');
	}

	if (fn.docblock.throws.length > 0) {
		lines.push('## Throws');
		lines.push('');
		fn.docblock.throws.forEach((throwTag) => {
			lines.push(
				`- \`${throwTag.type}\`${throwTag.description ? `: ${escapeMdxText(throwTag.description)}` : ''}`
			);
		});
		lines.push('');
	}

	if (relatedRecipes.length > 0) {
		lines.push('## Recipes');
		lines.push('');
		relatedRecipes.forEach((recipe) => {
			lines.push(`- [${recipe.title}](${recipe.uri})`);
		});
		lines.push('');
	}

	lines.push('## Source');
	lines.push('');
	if (sourceUrl) {
		lines.push(`- [\`${fn.file}:${fn.line}\`](${sourceUrl})`);
	} else {
		lines.push(`- \`${fn.file}:${fn.line}\``);
	}
	lines.push('');
	lines.push('```php');
	lines.push(fn.sourceSnippet);
	lines.push('```');
	lines.push('');

	return lines.join('\n');
}

function renderFunctionsIndex(functions) {
	const fallbackGroups = [
		{
			label: 'Registration',
			match: (name) =>
				name.startsWith('register_graphql_') ||
				name === 'get_graphql_register_action' ||
				name === 'rename_graphql_field' ||
				name === 'rename_graphql_type',
		},
		{
			label: 'Deregistration',
			match: (name) => name.startsWith('deregister_graphql_'),
		},
		{
			label: 'Requests and Endpoint',
			match: (name) =>
				name === 'graphql' ||
				name === 'do_graphql_request' ||
				name === 'is_graphql_request' ||
				name === 'is_graphql_http_request' ||
				name === 'graphql_get_endpoint' ||
				name === 'graphql_get_endpoint_url' ||
				name === 'graphql_get_nonce',
		},
		{
			label: 'Formatting and Validation',
			match: (name) =>
				name === 'graphql_format_name' ||
				name === 'graphql_format_field_name' ||
				name === 'graphql_format_type_name' ||
				name === 'is_valid_graphql_name',
		},
		{
			label: 'Settings and Admin',
			match: (name) =>
				name.startsWith('register_graphql_settings_') ||
				name === 'get_graphql_setting' ||
				name === 'register_graphql_admin_notice' ||
				name === 'get_graphql_admin_notices' ||
				name === 'graphql_debug',
		},
		{
			label: 'Polyfills',
			match: (name) => name === 'str_starts_with' || name === 'str_ends_with',
		},
	];

	const toLabelCase = (value) =>
		value
			.split(/[_-]+/)
			.filter(Boolean)
			.map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
			.join(' ');

	const normalizeFunctionGroupLabel = (rawLabel) => {
		if (typeof rawLabel !== 'string') {
			return null;
		}

		const trimmed = rawLabel.trim().replace(/\s+/g, ' ');
		if (!trimmed) {
			return null;
		}

		if (/^[a-z0-9_-]+$/i.test(trimmed)) {
			return toLabelCase(trimmed);
		}

		return trimmed;
	};

	const grouped = new Map();

	functions.forEach((fn) => {
		const explicitGroup = normalizeFunctionGroupLabel(fn.docblock.functionGroup);
		const groupLabel =
			explicitGroup ||
			fallbackGroups.find((candidate) => candidate.match(fn.name))?.label ||
			'Other';

		if (!grouped.has(groupLabel)) {
			grouped.set(groupLabel, []);
		}
		grouped.get(groupLabel).push(fn);
	});

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push('title: Functions');
	lines.push('---');
	lines.push('');
	lines.push('# Functions');
	lines.push('');
	lines.push(
		'The functions documented below are provided by WPGraphQL to extend the schema or interact with the GraphQL API.'
	);
	lines.push('');

	const fallbackOrder = fallbackGroups.map((group) => group.label);
	const orderedLabels = [];

	fallbackOrder.forEach((label) => {
		if (grouped.has(label)) {
			orderedLabels.push(label);
		}
	});

	const customLabels = Array.from(grouped.keys())
		.filter((label) => !fallbackOrder.includes(label) && label !== 'Other')
		.sort((a, b) => a.localeCompare(b));
	orderedLabels.push(...customLabels);

	if (grouped.has('Other')) {
		orderedLabels.push('Other');
	}

	orderedLabels.forEach((groupLabel) => {
		lines.push(`## ${groupLabel}`);
		lines.push('');
		grouped
			.get(groupLabel)
			.sort((a, b) => a.name.localeCompare(b.name))
			.forEach((fn) => {
				const slug = slugFromFunctionName(fn.name);
				lines.push(`- [\`${fn.name}\`](/functions/${slug})`);
			});
		lines.push('');
	});

	return lines.join('\n');
}

function renderLintMarkdown({ pluginSlug, lint }) {
	const errors = Array.isArray(lint.errors) ? lint.errors : [];
	const warnings = Array.isArray(lint.warnings) ? lint.warnings : [];
	const allItems = [...errors, ...warnings];

	const lines = [];
	lines.push(`# Function Docs Lint Report: ${pluginSlug}`);
	lines.push('');
	lines.push('## Summary');
	lines.push('');
	lines.push(`- Errors: ${errors.length}`);
	lines.push(`- Warnings: ${warnings.length}`);
	lines.push(`- Total findings: ${allItems.length}`);
	lines.push('');

	if (allItems.length === 0) {
		lines.push('No lint findings.');
		lines.push('');
		return lines.join('\n');
	}

	lines.push('## Findings');
	lines.push('');
	allItems.forEach((item) => {
		lines.push(`- **Function:** \`${item.function}\``);
		lines.push(`  - Severity: ${errors.includes(item) ? 'error' : 'warning'}`);
		lines.push(`  - Type: \`${item.type}\``);
		lines.push(`  - Message: ${item.message}`);
		lines.push(`  - Source: \`${item.file}\` (line ${item.line})`);
	});
	lines.push('');

	return lines.join('\n');
}

function writeOutputs({
	docsDir,
	functions,
	lint,
	repositoryUrl,
	repositoryRef,
	validateOnly,
}) {
	const generatedDir = path.join(docsDir, 'generated');
	const functionsDir = path.join(docsDir, 'functions');
	const filesToWrite = [];

	const indexPayload = {
		plugin: 'wp-graphql',
		generatedAt: new Date().toISOString(),
		stats: {
			totalFunctions: functions.length,
		},
		lint,
		functions: functions.map((fn) => ({
			name: fn.name,
			slug: slugFromFunctionName(fn.name),
			file: fn.file,
			line: fn.line,
			group: fn.docblock.functionGroup || null,
			relatedRecipes: Array.isArray(fn.relatedRecipes)
				? fn.relatedRecipes.map((recipe) => ({
						title: recipe.title,
						uri: recipe.uri,
					}))
				: [],
			since: fn.docblock.since,
			signature: `${fn.signature};`,
			description: fn.docblock.description,
		})),
	};

	filesToWrite.push({
		path: path.join(generatedDir, 'functions-index.json'),
		content: `${JSON.stringify(indexPayload, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'functions-lint.json'),
		content: `${JSON.stringify(lint, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'functions-lint.md'),
		content: `${renderLintMarkdown({ pluginSlug: 'wp-graphql', lint })}\n`,
	});
	filesToWrite.push({
		path: path.join(functionsDir, 'index.md'),
		content: renderFunctionsIndex(functions),
	});

	functions.forEach((fn) => {
		filesToWrite.push({
			path: path.join(functionsDir, `${slugFromFunctionName(fn.name)}.md`),
			content: renderFunctionDoc(fn, repositoryUrl, repositoryRef),
		});
	});

	const expectedFunctionFiles = new Set(
		filesToWrite
			.filter((file) => file.path.startsWith(functionsDir))
			.map((file) => path.basename(file.path))
	);

	if (validateOnly) {
		const changedFiles = filesToWrite
			.filter((file) => fs.existsSync(file.path))
			.filter((file) => fs.readFileSync(file.path, 'utf8') !== file.content)
			.map((file) => path.relative(process.cwd(), file.path));

		const staleFiles = listMarkdownFiles(functionsDir)
			.filter((filePath) => !expectedFunctionFiles.has(path.basename(filePath)))
			.map((filePath) => path.relative(process.cwd(), filePath));

		if (changedFiles.length > 0 || staleFiles.length > 0) {
			const staleSection =
				staleFiles.length > 0
					? `\nStale files:\n${staleFiles.map((item) => `- ${item}`).join('\n')}`
					: '';
			throw new Error(
				`Generated function docs are stale. Re-run function docs generator. Changed files:\n${changedFiles
					.map((item) => `- ${item}`)
					.join('\n')}${staleSection}`
			);
		}

		return;
	}

	ensureDir(generatedDir);
	ensureDir(functionsDir);

	listMarkdownFiles(functionsDir)
		.filter((filePath) => !expectedFunctionFiles.has(path.basename(filePath)))
		.forEach((filePath) => fs.unlinkSync(filePath));

	filesToWrite.forEach((file) => {
		fs.writeFileSync(file.path, file.content, 'utf8');
	});
}

function main() {
	const args = parseArgs();
	const repoRoot = process.cwd();
	const pluginSlug = args.plugin;

	if (!pluginSlug) {
		console.error('Error: --plugin is required');
		console.error('Usage: node scripts/functions/generate-function-docs.js --plugin=wp-graphql');
		process.exit(1);
	}

	const configPath = args.config
		? path.resolve(repoRoot, args.config)
		: path.resolve(repoRoot, 'scripts/hooks/plugin-config.json');
	const pluginConfigMap = readJson(configPath);
	const pluginConfig = pluginConfigMap[pluginSlug];
	const validateOnly = args['validate-only'] === 'true' || args['validate-only'] === true;

	if (!pluginConfig) {
		console.error(`Error: Plugin "${pluginSlug}" not found in ${configPath}`);
		process.exit(1);
	}

	const pluginDir = path.resolve(repoRoot, pluginConfig.pluginDir);
	const docsDir = path.resolve(repoRoot, pluginConfig.docsDir);
	const sourceFile = path.join(pluginDir, 'access-functions.php');
	const sourcePath = path.relative(repoRoot, sourceFile);

	if (!fs.existsSync(sourceFile)) {
		console.log(`No access-functions.php found for ${pluginSlug}; skipping function docs generation`);
		return;
	}

	const repositoryUrl = resolveRepositoryUrl({ args, pluginConfig, repoRoot });
	const repositoryRef = resolveRepositoryRef({ args, pluginConfig, repoRoot });
	const content = fs.readFileSync(sourceFile, 'utf8');
	const functions = extractFunctionsFromContent(content, sourcePath).sort((a, b) =>
		a.name.localeCompare(b.name)
	);
	const recipeRelations = loadRecipeRelations(docsDir);
	const functionsWithRecipes = functions.map((fn) => ({
		...fn,
		relatedRecipes: recipeRelations.byFunction[fn.name] || [],
	}));
	const lint = analyzeLint(functionsWithRecipes);

	writeOutputs({
		docsDir,
		functions: functionsWithRecipes,
		lint,
		repositoryUrl,
		repositoryRef,
		validateOnly,
	});

	if (lint.warnings.length > 0) {
		console.warn(`Warnings: ${lint.warnings.length}`);
	}

	console.log(`Generated function docs for ${pluginSlug}: ${functionsWithRecipes.length} functions`);
}

if (require.main === module) {
	main();
}

module.exports = {
	analyzeLint,
	extractFunctionsFromContent,
	parseDocblock,
	splitTopLevelParams,
};
